package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.Flushable;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterTest {

    private Appendable outFlushable;
    private Appendable outNonFlushable;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void flush_WithFlushableOut_CallsFlush() throws IOException {
        outFlushable = mock(Appendable.class, withSettings().extraInterfaces(Flushable.class));
        CSVPrinter printer = new CSVPrinter(outFlushable, format);

        // Cast to Flushable to verify flush call
        Flushable flushable = (Flushable) outFlushable;

        printer.flush();

        verify(flushable, times(1)).flush();
    }

    @Test
    void flush_WithNonFlushableOut_DoesNotThrow() throws IOException {
        outNonFlushable = mock(Appendable.class);
        CSVPrinter printer = new CSVPrinter(outNonFlushable, format);

        // flush should not throw or do anything if out is not Flushable
        assertDoesNotThrow(printer::flush);
    }
}
